// `clone_end_point`'s only ensures is `cloned_ep@ == ep@`, so the synthetic
// determinism obligation reduces to:
//   (r1@ == ep@) && (r2@ == ep@)  ==>  r1.id == r2.id.
// `EndPoint::view` is an open spec returning `AbstractEndPoint { id: self.id@ }`,
// so unfolding it on each side yields the per-field Seq equalities
// `r1.id@ == ep.id@` and `r2.id@ == ep.id@`. The two ensures conjuncts share
// no top-level trigger until we re-state them in the proof body; once we do,
// z3 can chain them transitively into `r1.id@ == r2.id@` and lift that
// through `=~=` to the Vec-level equality `r1.id == r2.id`.
assert((r1@ == ep@ && r2@ == ep@) ==> det_clone_end_point_equal(r1, r2)) by {
    if r1@ == ep@ && r2@ == ep@ {
        // Unfold `EndPoint::view` (it's `pub open spec`):
        //   r1@ == ep@  ==>  AbstractEndPoint{id: r1.id@} == AbstractEndPoint{id: ep.id@}
        //   ==>  r1.id@ == ep.id@   (single-field struct projection).
        assert(r1.id@ == ep.id@);
        assert(r2.id@ == ep.id@);
        // Transitivity of `==` on Seq<u8>.
        assert(r1.id@ == r2.id@);
        // Seq extensional equality — pins a useful trigger and re-asserts
        // the Seq-level equality so the Vec-equality axiom can fire.
        assert(r1.id@ =~= r2.id@);
    }
}
